B.a7V=new A.y(B.an,["Mornings and late afternoons are usually the calmest, with soft light for photos. Spring (April\u2013June) and early autumn (September\u2013October) are the most pleasant overall \u2014 alpine summer (July\u2013August) is best for high passes and lakes.","\u0421\u043f\u043e\u043a\u043e\u0439\u043d\u0435\u0435 \u0432\u0441\u0435\u0433\u043e \u0440\u0430\u043d\u043d\u0438\u043c \u0443\u0442\u0440\u043e\u043c \u0438\u043b\u0438 \u0431\u043b\u0438\u0436\u0435 \u043a \u0432\u0435\u0447\u0435\u0440\u0443 \u2014 \u043c\u044f\u0433\u043a\u0438\u0439 \u0441\u0432\u0435\u0442, \u043c\u0435\u043d\u044c\u0448\u0435 \u043b\u044e\u0434\u0435\u0439. \u0412\u0435\u0441\u043d\u0430 (\u0430\u043f\u0440\u0435\u043b\u044c\u2013\u0438\u044e\u043d\u044c) \u0438 \u0440\u0430\u043d\u043d\u044f\u044f \u043e\u0441\u0435\u043d\u044c (\u0441\u0435\u043d\u0442\u044f\u0431\u0440\u044c\u2013\u043e\u043a\u0442\u044f\u0431\u0440\u044c) \u2014 \u0441\u0430\u043c\u044b\u0435 \u043f\u0440\u0438\u044f\u0442\u043d\u044b\u0435 \u0441\u0435\u0437\u043e\u043d\u044b; \u0432\u044b\u0441\u043e\u043a\u0438\u0435 \u043f\u0435\u0440\u0435\u0432\u0430\u043b\u044b \u0438 \u0433\u043e\u0440\u043d\u044b\u0435 \u043e\u0437\u0451\u0440\u0430 \u043b\u0443\u0447\u0448\u0435 \u0441\u043c\u043e\u0442\u0440\u0435\u0442\u044c \u0432 \u0438\u044e\u043b\u0435\u2013\u0430\u0432\u0433\u0443\u0441\u0442\u0435.","\u042d\u0440\u0442\u0435 \u043c\u0435\u043d\u0435\u043d\u043a\u0438 \u0436\u0430\u043d\u0430 \u043a\u04af\u043d \u0431\u0430\u0442\u0430\u0430\u0440\u0434\u0430\u0433\u044b \u0443\u0431\u0430\u043a \u0442\u044b\u043d\u0447 \u0431\u043e\u043b\u043e\u0442, \u0441\u04af\u0440\u04e9\u0442 \u04af\u0447\u04af\u043d \u0436\u0430\u0440\u044b\u043a \u0436\u0443\u043c\u0448\u0430\u043a. \u0416\u0430\u0437 (\u0430\u043f\u0440\u0435\u043b\u044c\u2013\u0438\u044e\u043d\u044c) \u0436\u0430\u043d\u0430 \u043a\u04af\u0437\u0434\u04af\u043d \u0431\u0430\u0448\u044b (\u0441\u0435\u043d\u0442\u044f\u0431\u0440\u044c\u2013\u043e\u043a\u0442\u044f\u0431\u0440\u044c) \u2014 \u044d\u04a3 \u0436\u0430\u0439\u043b\u0443\u0443 \u043c\u0435\u0437\u0433\u0438\u043b; \u0431\u0438\u0439\u0438\u043a \u0430\u0448\u0443\u0443\u043b\u0430\u0440 \u0436\u0430\u043d\u0430 \u043a\u04e9\u043b\u0434\u04e9\u0440 \u0438\u044e\u043b\u044c\u2013\u0430\u0432\u0433\u0443\u0441\u0442\u0442\u0430 \u043a\u04e9\u0440\u0441\u04e9 \u0436\u0430\u043a\u0448\u044b."],t.w)
B.a2P=s(["Currency: Kyrgyz som (KGS). Cash is king outside cities; ATMs are plentiful in Bishkek, Osh, Karakol and Cholpon-Ata. Cards (Visa, MasterCard) work in supermarkets and good restaurants but rarely in mountain villages. Local sim cards are cheap (Beeline, MegaCom, O!) and a 4G data plan is enough for offline maps and chat."],t.s)
B.a58=s(["\u0412\u0430\u043b\u044e\u0442\u0430 \u2014 \u043a\u044b\u0440\u0433\u044b\u0437\u0441\u043a\u0438\u0439 \u0441\u043e\u043c (KGS). \u0417\u0430 \u043f\u0440\u0435\u0434\u0435\u043b\u0430\u043c\u0438 \u0433\u043e\u0440\u043e\u0434\u043e\u0432 \u043b\u0443\u0447\u0448\u0435 \u0438\u043c\u0435\u0442\u044c \u043d\u0430\u043b\u0438\u0447\u043d\u044b\u0435; \u0431\u0430\u043d\u043a\u043e\u043c\u0430\u0442\u044b \u0435\u0441\u0442\u044c \u0432 \u0411\u0438\u0448\u043a\u0435\u043a\u0435, \u041e\u0448\u0435, \u041a\u0430\u0440\u0430\u043a\u043e\u043b\u0435, \u0427\u043e\u043b\u043f\u043e\u043d-\u0410\u0442\u0435. \u041a\u0430\u0440\u0442\u044b Visa \u0438 MasterCard \u043f\u0440\u0438\u043d\u0438\u043c\u0430\u044e\u0442 \u0432 \u043a\u0440\u0443\u043f\u043d\u044b\u0445 \u043c\u0430\u0433\u0430\u0437\u0438\u043d\u0430\u0445 \u0438 \u0445\u043e\u0440\u043e\u0448\u0438\u0445 \u043a\u0430\u0444\u0435, \u043d\u043e \u0440\u0435\u0434\u043a\u043e \u0432 \u0433\u043e\u0440\u043d\u044b\u0445 \u0441\u0451\u043b\u0430\u0445. SIM-\u043a\u0430\u0440\u0442\u044b \u043c\u0435\u0441\u0442\u043d\u044b\u0445 \u043e\u043f\u0435\u0440\u0430\u0442\u043e\u0440\u043e\u0432 (Beeline, MegaCom, O!) \u0434\u0435\u0448\u0451\u0432\u044b\u0435, 4G-\u043f\u0430\u043a\u0435\u0442\u0430 \u0445\u0432\u0430\u0442\u0430\u0435\u0442 \u0434\u043b\u044f \u043e\u0444\u043b\u0430\u0439\u043d-\u043a\u0430\u0440\u0442 \u0438 \u043c\u0435\u0441\u0441\u0435\u043d\u0434\u0436\u0435\u0440\u043e\u0432."],t.s)
B.a1d=s(["\u0412\u0430\u043b\u044e\u0442\u0430 \u2014 \u043a\u044b\u0440\u0433\u044b\u0437 \u0441\u043e\u043c\u0443 (KGS). \u0428\u0430\u0430\u0440\u0434\u0430\u043d \u0442\u044b\u0448\u043a\u0430\u0440\u044b \u043d\u0430\u043a\u0442\u0430\u043b\u0430\u0439 \u0430\u043a\u0447\u0430 \u0430\u043b\u044b\u043f \u0436\u04af\u0440\u0433\u04e9\u043d \u0436\u0430\u043a\u0448\u044b; \u0431\u0430\u043d\u043a\u043e\u043c\u0430\u0442\u0442\u0430\u0440 \u0411\u0438\u0448\u043a\u0435\u043a\u0442\u0435, \u041e\u0448\u0442\u043e, \u041a\u0430\u0440\u0430\u043a\u043e\u043b \u0436\u0430\u043d\u0430 \u0427\u043e\u043b\u043f\u043e\u043d-\u0410\u0442\u0430\u0434\u0430 \u043a\u04e9\u043f. Visa \u0436\u0430\u043d\u0430 MasterCard \u043a\u0430\u0440\u0442\u0430\u043b\u0430\u0440\u044b \u0447\u043e\u04a3 \u0434\u04af\u043a\u04e9\u043d\u0434\u04e9\u0440\u0434\u04e9, \u043a\u0430\u0444\u0435\u043b\u0435\u0440\u0434\u0435 \u0438\u0448\u0442\u0435\u0439\u0442, \u0442\u043e\u043e \u0430\u0439\u044b\u043b\u0434\u0430\u0440\u044b\u043d\u0434\u0430 \u043a\u044d\u044d\u0434\u0435 \u0438\u0448\u0442\u0435\u0431\u0435\u0439\u0442. \u0416\u0435\u0440\u0433\u0438\u043b\u0438\u043a\u0442\u04af\u04af SIM-\u043a\u0430\u0440\u0442\u0430 (Beeline, MegaCom, O!) \u0430\u0440\u0437\u0430\u043d, 4G \u0442\u0430\u0440\u0438\u0444\u0438 \u043e\u0444\u043b\u0430\u0439\u043d \u043a\u0430\u0440\u0442\u0430 \u0436\u0430\u043d\u0430 \u0447\u0430\u0442 \u04af\u0447\u04af\u043d \u0436\u0435\u0442\u0435\u0442."],t.s)
B.a7W=new A.y(B.an,[B.a2P,B.a58,B.a1d],t.T)
B.a3p=s(["A yurt (boz \xfci) is a portable felt house used by nomads for centuries. Its frame is wooden lattice (kerege) topped by a circular crown \u2014 the tunduk \u2014 which is so important that it is on the Kyrgyz flag. Inside, the place opposite the door is the seat of honour; never step over food or the threshold."],t.s)
B.a4L=s(["\u042e\u0440\u0442\u0430 (\u0431\u043e\u0437 \u04af\u0439) \u2014 \u043f\u0435\u0440\u0435\u043d\u043e\u0441\u043d\u043e\u0435 \u0432\u043e\u0439\u043b\u043e\u0447\u043d\u043e\u0435 \u0436\u0438\u043b\u044c\u0451 \u043a\u043e\u0447\u0435\u0432\u043d\u0438\u043a\u043e\u0432. \u041a\u0430\u0440\u043a\u0430\u0441 \u0441\u043e\u0431\u0438\u0440\u0430\u0435\u0442\u0441\u044f \u0438\u0437 \u0434\u0435\u0440\u0435\u0432\u044f\u043d\u043d\u043e\u0439 \u0440\u0435\u0448\u0451\u0442\u043a\u0438 \u043a\u0435\u0440\u0435\u0433\u0435, \u043d\u0430\u0432\u0435\u0440\u0445\u0443 \u2014 \u043a\u0440\u0443\u0433\u043b\u044b\u0439 \u043a\u0443\u043f\u043e\u043b \u0442\u0443\u043d\u0434\u0443\u043a, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0438\u0437\u043e\u0431\u0440\u0430\u0436\u0451\u043d \u043d\u0430 \u0444\u043b\u0430\u0433\u0435 \u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d\u0430. \u041c\u0435\u0441\u0442\u043e \u043d\u0430\u043f\u0440\u043e\u0442\u0438\u0432 \u0432\u0445\u043e\u0434\u0430 \u2014 \u043f\u043e\u0447\u0451\u0442\u043d\u043e\u0435; \u0447\u0435\u0440\u0435\u0437 \u0435\u0434\u0443 \u0438 \u043f\u043e\u0440\u043e\u0433 \u043d\u0435 \u043f\u0435\u0440\u0435\u0441\u0442\u0443\u043f\u0430\u044e\u0442."],t.s)
B.a4N=s(["\u0411\u043e\u0437 \u04af\u0439 \u2014 \u043a\u044b\u043b\u044b\u043c\u0434\u0430\u0440 \u0431\u043e\u044e \u043a\u04e9\u0447\u043c\u04e9\u043d\u0434\u04e9\u0440 \u043f\u0430\u0439\u0434\u0430\u043b\u0430\u043d\u0433\u0430\u043d \u043a\u0438\u0439\u0438\u0437 \u04af\u0439. \u041a\u0430\u0440\u043a\u0430\u0441\u044b \u043a\u0435\u0440\u0435\u0433\u0435\u0434\u0435\u043d \u0442\u0443\u0440\u0430\u0442, \u04af\u0441\u0442\u04af\u043d\u0434\u04e9 \u0442\u0435\u0433\u0435\u0440\u0435\u043a \u0442\u04af\u043d\u0434\u04af\u043a \u2014 \u0430\u043b \u043a\u044b\u0440\u0433\u044b\u0437 \u0436\u0435\u043b\u0435\u0433\u0438\u043d\u0434\u0435 \u0434\u0430 \u0447\u0430\u0433\u044b\u043b\u0434\u044b\u0440\u044b\u043b\u0433\u0430\u043d. \u042d\u0448\u0438\u043a\u0442\u0438\u043d \u043c\u0430\u04a3\u0434\u0430\u0439\u044b\u043d\u0434\u0430\u0433\u044b \u043e\u0440\u0443\u043d \u0443\u0440\u043c\u0430\u0442\u0442\u0443\u0443 \u0431\u043e\u043b\u0443\u043f \u0441\u0430\u043d\u0430\u043b\u0430\u0442; \u0442\u0430\u043c\u0430\u043a \u043c\u0435\u043d\u0435\u043d \u0431\u043e\u0441\u043e\u0433\u043e\u0434\u043e\u043d \u0430\u0442\u0442\u0430\u0431\u0430\u0439\u0442."],t.s)
B.a7Y=new A.y(B.an,[B.a3p,B.a4L,B.a4N],t.T)
B.a1U=s(["Glad to help. Travel safely and respect the places \u2014 they remember kind visitors.","You are welcome! Tell your friends to come too \u2014 Kyrgyzstan loves curious travellers."],t.s)
B.a5e=s(["\u0420\u0430\u0434 \u043f\u043e\u043c\u043e\u0447\u044c! \u0425\u043e\u0440\u043e\u0448\u0435\u0439 \u0434\u043e\u0440\u043e\u0433\u0438 \u0438 \u0431\u0435\u0440\u0435\u0433\u0438\u0442\u0435 \u044d\u0442\u0438 \u043c\u0435\u0441\u0442\u0430 \u2014 \u043e\u043d\u0438 \u043f\u043e\u043c\u043d\u044f\u0442 \u0434\u043e\u0431\u0440\u044b\u0445 \u0433\u043e\u0441\u0442\u0435\u0439.","\u041f\u043e\u0436\u0430\u043b\u0443\u0439\u0441\u0442\u0430! \u0412\u043e\u0437\u0432\u0440\u0430\u0449\u0430\u0439\u0442\u0435\u0441\u044c \u0438 \u0437\u043e\u0432\u0438\u0442\u0435 \u0434\u0440\u0443\u0437\u0435\u0439 \u2014 \u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d \u043b\u044e\u0431\u0438\u0442 \u043b\u044e\u0431\u043e\u043f\u044b\u0442\u043d\u044b\u0445."],t.s)
B.a21=s(["\u0416\u0430\u0440\u0434\u0430\u043c \u0431\u0435\u0440\u04af\u04af\u0433\u04e9 \u043a\u0443\u0431\u0430\u043d\u044b\u0447\u0442\u0430\u043c\u044b\u043d! \u0416\u043e\u043b\u0443\u04a3\u0443\u0437 \u0430\u0447\u044b\u043a, \u0436\u0435\u0440\u043b\u0435\u0440\u0434\u0438 \u0441\u044b\u0439\u043b\u0430\u043f \u0431\u0430\u0440\u044b\u04a3\u044b\u0437 \u2014 \u0430\u043b\u0430\u0440 \u043c\u0435\u0439\u043c\u0430\u043d\u0447\u044b\u043b \u043a\u043e\u043d\u043e\u043a\u0442\u043e\u0440\u0434\u0443\u043d \u044d\u0441\u0438\u043d \u0436\u043e\u0433\u043e\u0442\u043f\u043e\u0439\u0442.","\u042d\u0447 \u043d\u0435\u0440\u0441\u0435 \u044d\u043c\u0435\u0441! \u0414\u043e\u0441\u0442\u043e\u0440\u0443\u04a3\u0443\u0437\u0434\u0443 \u0434\u0430 \u0447\u0430\u043a\u044b\u0440\u044b\u04a3\u044b\u0437 \u2014 \u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d \u0436\u0430\u04a3\u044b \u0434\u043e\u0441\u0442\u043e\u0440\u0434\u043e\u043d \u043a\u0443\u0431\u0430\u043d\u0430\u0442."],t.s)
B.a7Z=new A.y(B.an,[B.a1U,B.a5e,B.a21],t.T)
B.a3B=s(["Best general windows for travel:\n\u2022 Spring (April\u2013June): green pastures, wildflowers, rushing rivers.\n\u2022 Summer (July\u2013August): the only safe time for high passes and remote lakes (Ala-Kul, Kel-Suu, Son-Kul).\n\u2022 Autumn (September\u2013October): clearest air, golden walnut groves in the south.\n\u2022 Winter (November\u2013March): skiing at Karakol, ice on Issyk-Kul gulfs (the lake itself rarely freezes), short days, very cold mountains."],t.s)
B.a23=s(["\u041b\u0443\u0447\u0448\u0438\u0435 \u0441\u0435\u0437\u043e\u043d\u044b \u0434\u043b\u044f \u043f\u043e\u0435\u0437\u0434\u043e\u043a:\n\u2022 \u0412\u0435\u0441\u043d\u0430 (\u0430\u043f\u0440\u0435\u043b\u044c\u2013\u0438\u044e\u043d\u044c): \u0437\u0435\u043b\u0451\u043d\u044b\u0435 \u043f\u0430\u0441\u0442\u0431\u0438\u0449\u0430, \u043f\u043e\u043b\u0435\u0432\u044b\u0435 \u0446\u0432\u0435\u0442\u044b, \u0431\u0443\u0440\u043d\u044b\u0435 \u0440\u0435\u043a\u0438.\n\u2022 \u041b\u0435\u0442\u043e (\u0438\u044e\u043b\u044c\u2013\u0430\u0432\u0433\u0443\u0441\u0442): \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u043e\u0435 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u043e\u0435 \u0432\u0440\u0435\u043c\u044f \u0434\u043b\u044f \u0432\u044b\u0441\u043e\u043a\u0438\u0445 \u043f\u0435\u0440\u0435\u0432\u0430\u043b\u043e\u0432 \u0438 \u0433\u043e\u0440\u043d\u044b\u0445 \u043e\u0437\u0451\u0440 (\u0410\u043b\u0430-\u041a\u0443\u043b\u044c, \u041a\u0451\u043b\u044c-\u0421\u0443\u0443, \u0421\u043e\u043d-\u041a\u0443\u043b\u044c).\n\u2022 \u041e\u0441\u0435\u043d\u044c (\u0441\u0435\u043d\u0442\u044f\u0431\u0440\u044c\u2013\u043e\u043a\u0442\u044f\u0431\u0440\u044c): \u043f\u0440\u043e\u0437\u0440\u0430\u0447\u043d\u044b\u0439 \u0432\u043e\u0437\u0434\u0443\u0445, \u0437\u043e\u043b\u043e\u0442\u044b\u0435 \u043e\u0440\u0435\u0445\u043e\u0432\u044b\u0435 \u0440\u043e\u0449\u0438 \u043d\u0430 \u044e\u0433\u0435.\n\u2022 \u0417\u0438\u043c\u0430 (\u043d\u043e\u044f\u0431\u0440\u044c\u2013\u043c\u0430\u0440\u0442): \u0433\u043e\u0440\u043d\u044b\u0435 \u043b\u044b\u0436\u0438 \u0432 \u041a\u0430\u0440\u0430\u043a\u043e\u043b\u0435, \u043b\u0451\u0434 \u043d\u0430 \u0438\u0441\u0441\u044b\u043a-\u043a\u0443\u043b\u044c\u0441\u043a\u0438\u0445 \u0437\u0430\u043b\u0438\u0432\u0430\u0445 (\u0441\u0430\u043c\u043e \u043e\u0437\u0435\u0440\u043e \u043f\u043e\u0447\u0442\u0438 \u043d\u0435 \u0437\u0430\u043c\u0435\u0440\u0437\u0430\u0435\u0442), \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0435 \u0434\u043d\u0438, \u043e\u0447\u0435\u043d\u044c \u0445\u043e\u043b\u043e\u0434\u043d\u044b\u0435 \u0433\u043e\u0440\u044b."],t.s)
B.a4t=s(["\u0421\u0430\u044f\u043a\u0430\u0442 \u04af\u0447\u04af\u043d \u044d\u04a3 \u0436\u0430\u043a\u0448\u044b \u043c\u0435\u0437\u0433\u0438\u043b\u0434\u0435\u0440:\n\u2022 \u0416\u0430\u0437 (\u0430\u043f\u0440\u0435\u043b\u044c\u2013\u0438\u044e\u043d\u044c): \u0436\u0430\u0448\u044b\u043b \u0436\u0430\u0439\u043b\u043e\u043e\u043b\u043e\u0440, \u0442\u0430\u043b\u0430\u0430 \u0433\u04af\u043b\u0434\u04e9\u0440\u04af, \u044b\u043b\u0434\u0430\u043c \u0434\u0430\u0440\u044b\u044f\u043b\u0430\u0440.\n\u2022 \u0416\u0430\u0439 (\u0438\u044e\u043b\u044c\u2013\u0430\u0432\u0433\u0443\u0441\u0442): \u0431\u0438\u0439\u0438\u043a \u0430\u0448\u0443\u0443\u043b\u0430\u0440 \u0436\u0430\u043d\u0430 \u0442\u043e\u043e\u043b\u0443\u0443 \u043a\u04e9\u043b\u0434\u04e9\u0440\u0433\u04e9 (\u0410\u043b\u0430-\u041a\u04e9\u043b, \u041a\u0435\u043b\u044c-\u0421\u0443\u0443, \u0421\u043e\u043d-\u041a\u04e9\u043b) \u0436\u0430\u043b\u0433\u044b\u0437 \u043a\u043e\u043e\u043f\u0441\u0443\u0437 \u0443\u0431\u0430\u043a.\n\u2022 \u041a\u04af\u0437 (\u0441\u0435\u043d\u0442\u044f\u0431\u0440\u044c\u2013\u043e\u043a\u0442\u044f\u0431\u0440\u044c): \u0442\u0430\u0437\u0430 \u0430\u0431\u0430, \u0442\u04af\u0448\u0442\u04af\u043a\u0442\u04e9 \u0441\u0430\u0440\u044b \u0436\u0430\u04a3\u0433\u0430\u043a \u0442\u043e\u043a\u043e\u0439\u043b\u043e\u0440\u0443.\n\u2022 \u041a\u044b\u0448 (\u043d\u043e\u044f\u0431\u0440\u044c\u2013\u043c\u0430\u0440\u0442): \u041a\u0430\u0440\u0430\u043a\u043e\u043b \u043b\u044b\u0436\u0430\u0441\u044b, \u042b\u0441\u044b\u043a-\u041a\u04e9\u043b\u0434\u04af\u043d \u0431\u0443\u043b\u0443\u04a3\u0434\u0430\u0440\u044b\u043d\u0434\u0430 \u043c\u0443\u0437 (\u043a\u04e9\u043b\u0434\u04af\u043d \u04e9\u0437\u04af \u0434\u044d\u044d\u0440\u043b\u0438\u043a \u0442\u043e\u04a3\u0431\u043e\u0439\u0442), \u043a\u04af\u043d \u043a\u044b\u0441\u043a\u0430, \u0442\u043e\u043e\u0434\u043e \u0430\u0431\u0434\u0430\u043d \u0441\u0443\u0443\u043a."],t.s)
