B.a81=new A.y(B.an,["Guide joke","\u0428\u0443\u0442\u043a\u0430 \u043e\u0442 \u0433\u0438\u0434\u0430","\u0416\u043e\u043b \u043a\u04e9\u0440\u0441\u04e9\u0442\u043a\u04af\u0447\u0442\u04af\u043d \u0442\u0430\u043c\u0430\u0448\u0430\u0441\u044b"],t.w)
B.a82=new A.y(B.an,['Pick any of them and ask about its history, rules, route, traditions or just say "tell me about it".',"\u0412\u044b\u0431\u0435\u0440\u0438\u0442\u0435 \u043b\u044e\u0431\u043e\u0435 \u0438 \u0441\u043f\u0440\u043e\u0441\u0438\u0442\u0435 \u043f\u0440\u043e \u0438\u0441\u0442\u043e\u0440\u0438\u044e, \u043f\u0440\u0430\u0432\u0438\u043b\u0430, \u043c\u0430\u0440\u0448\u0440\u0443\u0442, \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u2014 \u0438\u043b\u0438 \u043f\u0440\u043e\u0441\u0442\u043e \u0441\u043a\u0430\u0436\u0438\u0442\u0435 \xab\u0440\u0430\u0441\u0441\u043a\u0430\u0436\u0438\xbb.","\u041a\u0430\u0430\u043b\u0430\u0433\u0430\u043d\u044b\u043d \u0442\u0430\u043d\u0434\u0430\u043f \u0442\u0430\u0440\u044b\u0445, \u044d\u0440\u0435\u0436\u0435, \u0436\u043e\u043b, \u0441\u0430\u043b\u0442 \u0436\u04e9\u043d\u04af\u043d\u0434\u04e9 \u0441\u0443\u0440\u0430\u0441\u0430\u04a3\u044b\u0437 \u0431\u043e\u043b\u043e\u0442 \u2014 \u0436\u0435 \u0436\u04e9\u043d \u0433\u0430\u043d\u0430 \xab\u0430\u0439\u0442\u044b\u043f \u0431\u0435\u0440\xbb \u0434\u0435\u043f \u0436\u0430\u0437\u044b\u04a3\u044b\u0437."],t.w)
B.a2y=s(["Kyrgyzstan is friendly and overall safe. Common-sense rules: keep belongings close in Bishkek bazaars and minibuses, do not leave gear unattended at trailheads, and ask before crossing pastures (shepherds and dogs prefer to know you). Mountain roads can be rough \u2014 let someone know your route before going off-grid."],t.s)
B.a4O=s(["\u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d \u0433\u043e\u0441\u0442\u0435\u043f\u0440\u0438\u0438\u043c\u043d\u044b\u0439 \u0438 \u0432 \u0446\u0435\u043b\u043e\u043c \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u044b\u0439. \u0411\u0430\u0437\u043e\u0432\u044b\u0435 \u0441\u043e\u0432\u0435\u0442\u044b: \u043d\u0430 \u0431\u0438\u0448\u043a\u0435\u043a\u0441\u043a\u0438\u0445 \u0431\u0430\u0437\u0430\u0440\u0430\u0445 \u0438 \u0432 \u043c\u0430\u0440\u0448\u0440\u0443\u0442\u043a\u0430\u0445 \u0434\u0435\u0440\u0436\u0438\u0442\u0435 \u0432\u0435\u0449\u0438 \u043f\u0440\u0438 \u0441\u0435\u0431\u0435; \u043d\u0430 \u0441\u0442\u0430\u0440\u0442\u0435 \u0442\u0440\u0435\u043a\u0438\u043d\u0433\u0430 \u043d\u0435 \u043e\u0441\u0442\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u0440\u044e\u043a\u0437\u0430\u043a\u0438 \u0431\u0435\u0437 \u043f\u0440\u0438\u0441\u043c\u043e\u0442\u0440\u0430; \u043f\u0435\u0440\u0435\u0441\u0435\u043a\u0430\u044f \u043f\u0430\u0441\u0442\u0431\u0438\u0449\u0430, \u043f\u0440\u0435\u0434\u0443\u043f\u0440\u0435\u0434\u0438\u0442\u0435 \u0447\u0430\u0431\u0430\u043d\u0430 \u2014 \u0441\u043e\u0431\u0430\u043a\u0438 \u043b\u0443\u0447\u0448\u0435 \u0440\u0430\u0431\u043e\u0442\u0430\u044e\u0442, \u043a\u043e\u0433\u0434\u0430 \u0445\u043e\u0437\u044f\u0438\u043d \u0432 \u043a\u0443\u0440\u0441\u0435. \u0413\u043e\u0440\u043d\u044b\u0435 \u0434\u043e\u0440\u043e\u0433\u0438 \u0431\u044b\u0432\u0430\u044e\u0442 \u0441\u043b\u043e\u0436\u043d\u044b\u043c\u0438 \u2014 \u043e\u0441\u0442\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u043c\u0430\u0440\u0448\u0440\u0443\u0442 \u0431\u043b\u0438\u0437\u043a\u0438\u043c \u043f\u0435\u0440\u0435\u0434 \u0434\u0430\u043b\u044c\u043d\u0438\u043c \u0432\u044b\u0435\u0437\u0434\u043e\u043c."],t.s)
B.a0z=s(["\u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d \u043c\u0435\u0439\u043c\u0430\u043d\u0447\u044b\u043b \u0436\u0430\u043d\u0430 \u043d\u0435\u0433\u0438\u0437\u0438 \u043a\u043e\u043e\u043f\u0441\u0443\u0437. \u041a\u0430\u0434\u0438\u043c\u043a\u0438 \u0441\u0430\u043a\u0442\u044b\u043a \u0447\u0430\u0440\u0430\u043b\u0430\u0440\u044b: \u0411\u0438\u0448\u043a\u0435\u043a\u0442\u0438\u043d \u0431\u0430\u0437\u0430\u0440\u043b\u0430\u0440\u044b\u043d\u0434\u0430, \u043c\u0430\u0440\u0448\u0440\u0443\u0442\u043a\u0430\u0434\u0430 \u043d\u0435\u0440\u0441\u0435\u043b\u0435\u0440\u0438\u04a3\u0438\u0437\u0434\u0438 \u0436\u0430\u043a\u044b\u043d \u0430\u043b\u044b\u043f \u0436\u04af\u0440\u04af\u04a3\u04af\u0437; \u0442\u0440\u0435\u043a \u0431\u0430\u0448\u044b\u043d\u0434\u0430 \u0440\u044e\u043a\u0437\u0430\u043a\u0442\u044b \u0436\u0430\u043b\u0433\u044b\u0437 \u043a\u0430\u043b\u0442\u044b\u0440\u0431\u0430\u04a3\u044b\u0437; \u0436\u0430\u0439\u044b\u0442\u0442\u0430\u043d \u04e9\u0442\u0441\u04e9\u04a3\u04af\u0437 \u043a\u043e\u0439\u0447\u0443\u0433\u0430 \u0431\u0438\u043b\u0433\u0438\u0437\u0438\u04a3\u0438\u0437 \u2014 \u0438\u0442\u0442\u0435\u0440 \u044d\u044d\u0441\u0438 \u0431\u0438\u043b\u0433\u0435\u043d\u0434\u0435 \u0433\u0430\u043d\u0430 \u0442\u044b\u043d\u0447. \u0422\u043e\u043e \u0436\u043e\u043b\u0434\u043e\u0440\u0443 \u043a\u044d\u044d\u0434\u0435 \u0442\u0430\u0442\u0430\u0430\u043b \u2014 \u0430\u043b\u044b\u0441 \u0431\u0430\u0440\u0430\u0440\u0434\u0430\u043d \u043c\u0443\u0440\u0434\u0430 \u043c\u0430\u0440\u0448\u0440\u0443\u0442\u0442\u0443 \u0436\u0430\u043a\u044b\u043d\u0434\u0430\u0440\u044b\u04a3\u044b\u0437\u0433\u0430 \u0430\u0439\u0442\u044b\u04a3\u044b\u0437."],t.s)
B.a83=new A.y(B.an,[B.a2y,B.a4O,B.a0z],t.T)
B.a3j=s(["I am offline and stick to Kyrgyzstan \u2014 sacred places, tourist sites, food, traditions, language. Ask me about Burana, Sulaiman-Too, Issyk-Kul, Ala-Archa, Tash-Rabat or Son-Kul and I will be in my element."],t.s)
B.a3a=s(["\u042f \u0440\u0430\u0431\u043e\u0442\u0430\u044e \u043e\u0444\u043b\u0430\u0439\u043d \u0438 \u0433\u043e\u0432\u043e\u0440\u044e \u0442\u043e\u043b\u044c\u043a\u043e \u043e \u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d\u0435 \u2014 \u0441\u0432\u044f\u0442\u044b\u0435 \u043c\u0435\u0441\u0442\u0430, \u0442\u0443\u0440\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0435 \u043b\u043e\u043a\u0430\u0446\u0438\u0438, \u0435\u0434\u0430, \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438, \u044f\u0437\u044b\u043a. \u0421\u043f\u0440\u043e\u0441\u0438\u0442\u0435 \u043c\u0435\u043d\u044f \u043f\u0440\u043e \u0411\u0443\u0440\u0430\u043d\u0443, \u0421\u0443\u043b\u0430\u0439\u043c\u0430\u043d-\u0422\u043e\u043e, \u0418\u0441\u0441\u044b\u043a-\u041a\u0443\u043b\u044c, \u0410\u043b\u0430-\u0410\u0440\u0447\u0443, \u0422\u0430\u0448-\u0420\u0430\u0431\u0430\u0442 \u0438\u043b\u0438 \u0421\u043e\u043d-\u041a\u0443\u043b\u044c."],t.s)
B.a10=s(["\u041c\u0435\u043d \u043e\u0444\u043b\u0430\u0439\u043d\u043c\u044b\u043d \u0436\u0430\u043d\u0430 \u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d \u0442\u0443\u0443\u0440\u0430\u043b\u0443\u0443 \u0433\u0430\u043d\u0430 \u0441\u04af\u0439\u043b\u04e9\u0448\u04e9\u043c \u2014 \u044b\u0439\u044b\u043a \u0436\u0435\u0440\u043b\u0435\u0440, \u0442\u0443\u0440\u0438\u0441\u0442\u0442\u0438\u043a \u043e\u0431\u044a\u0435\u043a\u0442\u0442\u0435\u0440, \u0442\u0430\u043c\u0430\u043a-\u0430\u0448, \u0441\u0430\u043b\u0442\u0442\u0430\u0440, \u0442\u0438\u043b. \u0411\u0443\u0440\u0430\u043d\u0430, \u0421\u0443\u043b\u0430\u0439\u043c\u0430\u043d-\u0422\u043e\u043e, \u042b\u0441\u044b\u043a-\u041a\u04e9\u043b, \u0410\u043b\u0430-\u0410\u0440\u0447\u0430, \u0422\u0430\u0448-\u0420\u0430\u0431\u0430\u0442 \u0436\u0435 \u0421\u043e\u043d-\u041a\u04e9\u043b \u2014 \u043a\u0430\u0439\u0441\u044b\u043d\u044b\u0441\u044b\u043d \u0442\u0430\u043d\u0434\u0430\u0439\u0431\u044b\u0437?"],t.s)
B.a84=new A.y(B.an,[B.a3j,B.a3a,B.a10],t.T)
B.a2X=s(["Must-try Kyrgyz dishes:\n\u2022 Beshbarmak \u2014 boiled meat (lamb or horse) on flat noodles, the national dish.\n\u2022 Lagman \u2014 pulled noodles with vegetables and meat, perfect after a hike.\n\u2022 Manty \u2014 large steamed dumplings, juicy lamb-and-onion filling.\n\u2022 Plov \u2014 rice with carrots, lamb and cumin, slow-cooked in a kazan.\n\u2022 Shorpo \u2014 clear lamb broth with potatoes, the universal cure for tired travellers.\nDrinks: kymyz (fermented mare's milk, mildly sour), maksym (grain-based, summer favourite) and unstoppable amounts of black tea."],t.s)
B.a2K=s(["\u0427\u0442\u043e \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u043e \u043f\u043e\u043f\u0440\u043e\u0431\u043e\u0432\u0430\u0442\u044c:\n\u2022 \u0411\u0435\u0448\u0431\u0430\u0440\u043c\u0430\u043a \u2014 \u0432\u0430\u0440\u0451\u043d\u043e\u0435 \u043c\u044f\u0441\u043e (\u0431\u0430\u0440\u0430\u043d\u0438\u043d\u0430 \u0438\u043b\u0438 \u043a\u043e\u043d\u0438\u043d\u0430) \u043d\u0430 \u0448\u0438\u0440\u043e\u043a\u043e\u0439 \u043b\u0430\u043f\u0448\u0435, \u043d\u0430\u0446\u0438\u043e\u043d\u0430\u043b\u044c\u043d\u043e\u0435 \u0431\u043b\u044e\u0434\u043e.\n\u2022 \u041b\u0430\u0433\u043c\u0430\u043d \u2014 \u0432\u044b\u0442\u044f\u0436\u043d\u0430\u044f \u043b\u0430\u043f\u0448\u0430 \u0441 \u043e\u0432\u043e\u0449\u0430\u043c\u0438 \u0438 \u043c\u044f\u0441\u043e\u043c, \u0438\u0434\u0435\u0430\u043b\u044c\u043d\u043e \u043f\u043e\u0441\u043b\u0435 \u043f\u043e\u0445\u043e\u0434\u0430.\n\u2022 \u041c\u0430\u043d\u0442\u044b \u2014 \u043a\u0440\u0443\u043f\u043d\u044b\u0435 \u043f\u0430\u0440\u043e\u0432\u044b\u0435 \u043f\u0435\u043b\u044c\u043c\u0435\u043d\u0438 \u0441 \u0441\u043e\u0447\u043d\u043e\u0439 \u0431\u0430\u0440\u0430\u043d\u0438\u043d\u043e\u0439 \u0438 \u043b\u0443\u043a\u043e\u043c.\n\u2022 \u041f\u043b\u043e\u0432 \u2014 \u0440\u0438\u0441 \u0441 \u043c\u043e\u0440\u043a\u043e\u0432\u044c\u044e, \u0431\u0430\u0440\u0430\u043d\u0438\u043d\u043e\u0439 \u0438 \u0437\u0438\u0440\u043e\u0439, \u0442\u043e\u043c\u043b\u0451\u043d\u044b\u0439 \u0432 \u043a\u0430\u0437\u0430\u043d\u0435.\n\u2022 \u0428\u043e\u0440\u043f\u043e \u2014 \u043f\u0440\u043e\u0437\u0440\u0430\u0447\u043d\u044b\u0439 \u043c\u044f\u0441\u043d\u043e\u0439 \u0431\u0443\u043b\u044c\u043e\u043d \u0441 \u043a\u0430\u0440\u0442\u043e\u0448\u043a\u043e\u0439, \u043b\u0443\u0447\u0448\u0435\u0435 \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043e \u0434\u043b\u044f \u0443\u0441\u0442\u0430\u0432\u0448\u0435\u0433\u043e \u0442\u0443\u0440\u0438\u0441\u0442\u0430.\n\u041d\u0430\u043f\u0438\u0442\u043a\u0438: \u043a\u0443\u043c\u044b\u0441 (\u043a\u043e\u0431\u044b\u043b\u044c\u0435 \u043c\u043e\u043b\u043e\u043a\u043e, \u043a\u0438\u0441\u043b\u0438\u043d\u043a\u0430 \u0441 \u043f\u0443\u0437\u044b\u0440\u044c\u043a\u0430\u043c\u0438), \u043c\u0430\u043a\u0441\u044b\u043c (\u043d\u0430 \u043e\u0441\u043d\u043e\u0432\u0435 \u0437\u043b\u0430\u043a\u043e\u0432, \u043b\u0435\u0442\u043d\u0438\u0439 \u0445\u0438\u0442) \u0438 \u043b\u0438\u0442\u0440\u044b \u0447\u0451\u0440\u043d\u043e\u0433\u043e \u0447\u0430\u044f."],t.s)
B.a20=s(["\u0421\u04e9\u0437\u0441\u04af\u0437 \u0434\u0430\u0430\u043c \u0442\u0430\u0442\u043a\u0430\u043d\u044b\u04a3\u044b\u0437 \u043a\u0435\u0440\u0435\u043a \u0442\u0430\u043c\u0430\u043a\u0442\u0430\u0440:\n\u2022 \u0411\u0435\u0448\u0431\u0430\u0440\u043c\u0430\u043a \u2014 \u043a\u0430\u0439\u043d\u0430\u0442\u044b\u043b\u0433\u0430\u043d \u044d\u0442 (\u043a\u043e\u0439 \u0436\u0435 \u0436\u044b\u043b\u043a\u044b) \u043a\u0435\u0441\u043c\u0435 \u043c\u0435\u043d\u0435\u043d, \u0443\u043b\u0443\u0442\u0442\u0443\u043a \u0442\u0430\u043c\u0430\u043a.\n\u2022 \u041b\u0430\u0433\u043c\u0430\u043d \u2014 \u0442\u0430\u0440\u0442\u043a\u0430\u043d \u043a\u0435\u0441\u043c\u0435, \u044d\u0442-\u0436\u0430\u0448\u044b\u043b\u0447\u0430 \u043c\u0435\u043d\u0435\u043d, \u0443\u0437\u0430\u043a \u0436\u043e\u043b\u0434\u043e\u043d \u043a\u0438\u0439\u0438\u043d \u044d\u04a3 \u0441\u043e\u043d\u0443\u043d.\n\u2022 \u041c\u0430\u043d\u0442\u044b \u2014 \u0448\u0438\u0440\u0435\u043b\u04af\u04af \u043a\u043e\u0439 \u044d\u0442\u0438 \u0436\u0430\u043d\u0430 \u043f\u0438\u044f\u0437 \u0441\u0430\u043b\u044b\u043d\u0433\u0430\u043d \u0431\u0443\u0443\u0434\u0430 \u0431\u044b\u0448\u043a\u0430\u043d \u043a\u0430\u0448\u044b\u043a \u0447\u0435\u043b\u0435\u0440.\n\u2022 \u041f\u0430\u043b\u043e\u043e \u2014 \u0441\u0430\u0431\u0438\u0437, \u043a\u043e\u0439 \u044d\u0442\u0438, \u0437\u0438\u0440\u0430 \u043c\u0435\u043d\u0435\u043d, \u043a\u0430\u0437\u0430\u043d\u0434\u0430 \u0436\u0430\u0439 \u0431\u044b\u0448\u043a\u0430\u043d \u043a\u04af\u0440\u04af\u0447.\n\u2022 \u0428\u043e\u0440\u043f\u043e \u2014 \u0442\u0430\u0437\u0430 \u044d\u0442 \u0441\u043e\u0440\u043f\u043e \u043a\u0430\u0440\u0442\u043e\u0448\u043a\u0430 \u043c\u0435\u043d\u0435\u043d, \u0447\u0430\u0440\u0447\u0430\u0433\u0430\u043d \u043c\u0443\u0441\u0430\u043f\u044b\u0440\u0433\u0430 \u044d\u04a3 \u0436\u0430\u043a\u0448\u044b \u0434\u0430\u0440\u044b.\n\u0421\u0443\u0443\u0441\u0443\u043d\u0434\u0443\u043a\u0442\u0430\u0440: \u043a\u044b\u043c\u044b\u0437 (\u0431\u044d\u044d \u0441\u04af\u0442\u04af, \u0430\u0447\u044b\u0440\u0430\u0430\u043a), \u043c\u0430\u043a\u0441\u044b\u043c (\u0431\u0443\u0443\u0434\u0430\u0439 \u0430\u0440\u0430\u043b\u0430\u0448, \u0436\u0430\u0439\u0434\u044b\u043d \u0434\u0430\u0430\u043c\u044b) \u0436\u0430\u043d\u0430 \u0441\u0430\u043d\u0441\u044b\u0437 \u043a\u04e9\u043f \u043a\u0430\u0440\u0430 \u0447\u0430\u0439."],t.s)
B.a85=new A.y(B.an,[B.a2X,B.a2K,B.a20],t.T)
B.a5c=s(["Hi! I am the offline guide for Sacred KG. Ask me anything about a sacred place, a tourist site or general travel in Kyrgyzstan and I will share rules, history, routes, and even a fun fact or two.","Hello, traveller! I work fully offline. Tell me a place name (Burana, Sulaiman-Too, Issyk-Kul, Tash-Rabat\u2026) or ask about food, money, language \u2014 anything Kyrgyz."],t.s)
B.a42=s(["\u0417\u0434\u0440\u0430\u0432\u0441\u0442\u0432\u0443\u0439\u0442\u0435! \u042f \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u0433\u0438\u0434 Sacred KG, \u0440\u0430\u0431\u043e\u0442\u0430\u044e \u043e\u0444\u043b\u0430\u0439\u043d. \u0421\u043f\u0440\u043e\u0441\u0438\u0442\u0435 \u043f\u0440\u043e \u043b\u044e\u0431\u043e\u0435 \u0441\u0432\u044f\u0442\u043e\u0435 \u0438\u043b\u0438 \u0442\u0443\u0440\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u043e\u0435 \u043c\u0435\u0441\u0442\u043e, \u043f\u0440\u043e \u0435\u0434\u0443, \u0432\u0430\u043b\u044e\u0442\u0443, \u0442\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u2014 \u043e\u0442\u0432\u0435\u0447\u0443 \u043f\u043e\u0434\u0440\u043e\u0431\u043d\u043e \u0438 \u0438\u043d\u043e\u0433\u0434\u0430 \u043f\u043e\u0434\u043a\u0438\u043d\u0443 \u0438\u043d\u0442\u0435\u0440\u0435\u0441\u043d\u044b\u0439 \u0444\u0430\u043a\u0442.","\u041f\u0440\u0438\u0432\u0435\u0442! \u0420\u0430\u0441\u0441\u043a\u0430\u0436\u0443 \u043f\u0440\u043e \u0411\u0443\u0440\u0430\u043d\u0443, \u0421\u0443\u043b\u0430\u0439\u043c\u0430\u043d-\u0422\u043e\u043e, \u0418\u0441\u0441\u044b\u043a-\u041a\u0443\u043b\u044c, \u0422\u0430\u0448-\u0420\u0430\u0431\u0430\u0442, \u0421\u043e\u043d-\u041a\u0443\u043b\u044c \u0438 \u043c\u043d\u043e\u0433\u043e\u0435 \u0434\u0440\u0443\u0433\u043e\u0435. \u041c\u043e\u0436\u0435\u0442\u0435 \u043f\u0438\u0441\u0430\u0442\u044c \u0441 \u043e\u043f\u0435\u0447\u0430\u0442\u043a\u0430\u043c\u0438 \u2014 \u044f \u043f\u043e\u0439\u043c\u0443."],t.s)
B.a5O=s(["\u0421\u0430\u043b\u0430\u043c\u0430\u0442\u0441\u044b\u0437\u0431\u044b! \u041c\u0435\u043d Sacred KG \u043a\u043e\u043b\u0434\u043e\u043d\u043c\u043e\u0441\u0443\u043d\u0443\u043d \u043e\u0444\u043b\u0430\u0439\u043d \u0436\u043e\u043b \u043a\u04e9\u0440\u0441\u04e9\u0442\u043a\u04af\u0447\u04af\u043c\u04af\u043d. \u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d\u0434\u044b\u043d \u044b\u0439\u044b\u043a \u0436\u0430\u043d\u0430 \u0442\u0443\u0440\u0438\u0441\u0442\u0442\u0438\u043a \u0436\u0435\u0440\u043b\u0435\u0440\u0438, \u0442\u0430\u043c\u0430\u043a-\u0430\u0448, \u0430\u043a\u0447\u0430, \u0442\u0438\u043b, \u0441\u0430\u043b\u0442\u0442\u0430\u0440 \u0436\u04e9\u043d\u04af\u043d\u0434\u04e9 \u0441\u0443\u0440\u0430\u0441\u0430\u04a3\u044b\u0437 \u2014 \u043a\u0435\u04a3\u0438\u0440\u0438 \u0430\u0439\u0442\u044b\u043f \u0431\u0435\u0440\u0435\u043c.","\u0421\u0430\u043b\u0430\u043c! \u0411\u0443\u0440\u0430\u043d\u0430, \u0421\u0443\u043b\u0430\u0439\u043c\u0430\u043d-\u0422\u043e\u043e, \u042b\u0441\u044b\u043a-\u041a\u04e9\u043b, \u0422\u0430\u0448-\u0420\u0430\u0431\u0430\u0442, \u0421\u043e\u043d-\u041a\u04e9\u043b \u2014 \u043a\u0430\u0439\u0441\u044b \u0436\u0435\u0440 \u0436\u04e9\u043d\u04af\u043d\u0434\u04e9 \u0441\u04af\u0439\u043b\u04e9\u0448\u04e9\u0431\u04af\u0437? \u0416\u0430\u0437\u0433\u0430\u043d\u0434\u0430 \u043a\u0430\u0442\u0430 \u043a\u0435\u0442\u0441\u0435 \u0434\u0430 \u0442\u04af\u0448\u04af\u043d\u04e9\u043c."],t.s)
B.a86=new A.y(B.an,[B.a5c,B.a42,B.a5O],t.T)
B.a40=s(["Nomadic life shapes Kyrgyz culture. Families move with their herds between winter villages and summer pastures (jailoo). On a jailoo you may be invited for kymyz, sourdough bread and chai \u2014 accept with both hands and at least one cup. Sheep, horses and yaks set the rhythm: shearing in spring, milk fermentation in summer, and the descent before snow."],t.s)
B.a5p=s(["\u041a\u043e\u0447\u0435\u0432\u043e\u0439 \u0443\u043a\u043b\u0430\u0434 \u0434\u043e \u0441\u0438\u0445 \u043f\u043e\u0440 \u0444\u043e\u0440\u043c\u0438\u0440\u0443\u0435\u0442 \u043a\u044b\u0440\u0433\u044b\u0437\u0441\u043a\u0443\u044e \u043a\u0443\u043b\u044c\u0442\u0443\u0440\u0443. \u0421\u0435\u043c\u044c\u0438 \u043a\u043e\u0447\u0443\u044e\u0442 \u0441\u043e \u0441\u0442\u0430\u0434\u0430\u043c\u0438 \u043c\u0435\u0436\u0434\u0443 \u0437\u0438\u043c\u043e\u0432\u043a\u043e\u0439 \u0438 \u043b\u0435\u0442\u043d\u0438\u043c \u043f\u0430\u0441\u0442\u0431\u0438\u0449\u0435\u043c \u2014 \u0434\u0436\u0430\u0439\u043b\u043e\u043e. \u041d\u0430 \u0434\u0436\u0430\u0439\u043b\u043e\u043e \u0432\u0430\u0441 \u043c\u043e\u0433\u0443\u0442 \u043f\u043e\u0437\u0432\u0430\u0442\u044c \u043d\u0430 \u043a\u0443\u043c\u044b\u0441, \u043b\u0435\u043f\u0451\u0448\u043a\u0443 \u0438 \u0447\u0430\u0439 \u2014 \u0431\u0435\u0440\u0438\u0442\u0435 \u043e\u0431\u0435\u0438\u043c\u0438 \u0440\u0443\u043a\u0430\u043c\u0438 \u0438 \u043e\u0431\u044f\u0437\u0430\u0442\u0435\u043b\u044c\u043d\u043e \u0445\u043e\u0442\u044f \u0431\u044b \u043e\u0434\u043d\u0443 \u043f\u0438\u0430\u043b\u0443. \u041e\u0432\u0446\u044b, \u043b\u043e\u0448\u0430\u0434\u0438, \u044f\u043a\u0438 \u0437\u0430\u0434\u0430\u044e\u0442 \u0440\u0438\u0442\u043c: \u0432\u0435\u0441\u043d\u0430 \u2014 \u0441\u0442\u0440\u0438\u0436\u043a\u0430, \u043b\u0435\u0442\u043e \u2014 \u043a\u0443\u043c\u044b\u0441, \u043e\u0441\u0435\u043d\u044c \u2014 \u0441\u043f\u0443\u0441\u043a \u043f\u0435\u0440\u0435\u0434 \u0441\u043d\u0435\u0433\u043e\u043c."],t.s)
B.a5o=s(["\u041a\u044b\u0440\u0433\u044b\u0437 \u043c\u0430\u0434\u0430\u043d\u0438\u044f\u0442\u044b\u043d \u043a\u04e9\u0447\u043c\u04e9\u043d \u0442\u0443\u0440\u043c\u0443\u0448 \u043a\u04af\u043d\u04af \u0431\u04af\u0433\u04af\u043d\u0433\u04e9 \u0447\u0435\u0439\u0438\u043d \u0442\u04af\u043f\u0442\u04e9\u0439\u0442. \u04ae\u0439-\u0431\u04af\u043b\u04e9\u043b\u04e9\u0440 \u043c\u0430\u043b \u043c\u0435\u043d\u0435\u043d \u043a\u044b\u0448\u043a\u044b \u0430\u0439\u044b\u043b\u0434\u0430\u043d \u0436\u0430\u0439\u043b\u043e\u043e\u0433\u043e \u043a\u04e9\u0447\u04af\u0448\u04e9\u0442. \u0416\u0430\u0439\u043b\u043e\u043e\u0434\u043e \u0441\u0438\u0437\u0434\u0438 \u043a\u044b\u043c\u044b\u0437\u0433\u0430, \u043d\u0430\u043d\u0433\u0430, \u0447\u0430\u0439\u0433\u0430 \u0447\u0430\u043a\u044b\u0440\u044b\u0448\u044b \u043c\u04af\u043c\u043a\u04af\u043d \u2014 \u044d\u043a\u0438 \u043a\u043e\u043b\u0434\u043e\u043f \u0430\u043b\u044b\u043f, \u0436\u043e\u043a \u0434\u0435\u0433\u0435\u043d\u0434\u0435 \u0431\u0438\u0440 \u0447\u044b\u043d\u044b \u0438\u0447\u0438\u04a3\u0438\u0437. \u041a\u043e\u0439, \u0436\u044b\u043b\u043a\u044b, \u0442\u043e\u043f\u043e\u0437 \u044b\u0440\u0433\u0430\u043a\u0442\u044b \u0431\u0435\u043b\u0433\u0438\u043b\u0435\u0439\u0442: \u0436\u0430\u0437\u0434\u0430 \u043a\u044b\u0440\u043a\u0443\u0443, \u0436\u0430\u0439\u044b\u043d\u0434\u0430 \u043a\u044b\u043c\u044b\u0437, \u043a\u04af\u0437\u0434\u04e9 \u043a\u0430\u0440 \u0436\u0430\u0430\u0440\u0434\u0430\u043d \u043c\u0443\u0440\u0443\u043d \u043a\u0430\u0439\u0440\u0430 \u0442\u04af\u0448\u04af\u04af."],t.s)
B.a87=new A.y(B.an,[B.a40,B.a5p,B.a5o],t.T)
B.a5l=s(["Useful Kyrgyz phrases:\n\u2022 Salam / Salamatsyzby \u2014 Hello / Hello (formal).\n\u2022 Rakhmat \u2014 Thank you.\n\u2022 Ooba / jok \u2014 Yes / no.\n\u2022 Kanchaa? \u2014 How much?\n\u2022 Kechiresiz \u2014 Excuse me / sorry.\n\u2022 Aman bolsun \u2014 May you be well (great farewell).\nRussian also works almost everywhere; English is common in tourist spots and caf\xe9s in Bishkek and Karakol."],t.s)
B.a3r=s(["\u041f\u043e\u043b\u0435\u0437\u043d\u044b\u0435 \u043a\u044b\u0440\u0433\u044b\u0437\u0441\u043a\u0438\u0435 \u0444\u0440\u0430\u0437\u044b:\n\u2022 \u0421\u0430\u043b\u0430\u043c / \u0421\u0430\u043b\u0430\u043c\u0430\u0442\u0441\u044b\u0437\u0431\u044b \u2014 \u041f\u0440\u0438\u0432\u0435\u0442 / \u0417\u0434\u0440\u0430\u0432\u0441\u0442\u0432\u0443\u0439\u0442\u0435 (\u0432\u0435\u0436\u043b\u0438\u0432\u043e).\n\u2022 \u0420\u0430\u0445\u043c\u0430\u0442 \u2014 \u0421\u043f\u0430\u0441\u0438\u0431\u043e.\n\u2022 \u041e\u043e\u0431\u0430 / \u0436\u043e\u043a \u2014 \u0414\u0430 / \u043d\u0435\u0442.\n\u2022 \u041a\u0430\u043d\u0447\u0430? \u2014 \u0421\u043a\u043e\u043b\u044c\u043a\u043e?\n\u2022 \u041a\u0435\u0447\u0438\u0440\u0435\u0441\u0438\u0437 \u2014 \u0418\u0437\u0432\u0438\u043d\u0438\u0442\u0435.\n\u2022 \u0410\u043c\u0430\u043d \u0431\u043e\u043b\u0441\u0443\u043d \u2014 \u0411\u0443\u0434\u044c\u0442\u0435 \u0437\u0434\u043e\u0440\u043e\u0432\u044b (\u0445\u043e\u0440\u043e\u0448\u0435\u0435 \u043f\u0440\u043e\u0449\u0430\u043d\u0438\u0435).\n\u0420\u0443\u0441\u0441\u043a\u0438\u0439 \u043f\u043e\u043d\u0438\u043c\u0430\u044e\u0442 \u043f\u043e\u0447\u0442\u0438 \u0432\u0435\u0437\u0434\u0435; \u0430\u043d\u0433\u043b\u0438\u0439\u0441\u043a\u0438\u0439 \u0440\u0430\u0441\u043f\u0440\u043e\u0441\u0442\u0440\u0430\u043d\u0451\u043d \u0432 \u0442\u0443\u0440\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043a\u0438\u0445 \u043c\u0435\u0441\u0442\u0430\u0445 \u0438 \u043a\u0430\u0444\u0435 \u0411\u0438\u0448\u043a\u0435\u043a\u0430 \u0438 \u041a\u0430\u0440\u0430\u043a\u043e\u043b\u0430."],t.s)
B.a1N=s(["\u041a\u043e\u043b\u0434\u043e\u043d\u0443\u043b\u0430 \u0442\u0443\u0440\u0433\u0430\u043d \u043a\u044b\u0440\u0433\u044b\u0437 \u0441\u04af\u0439\u043b\u04e9\u043c\u0434\u04e9\u0440:\n\u2022 \u0421\u0430\u043b\u0430\u043c / \u0421\u0430\u043b\u0430\u043c\u0430\u0442\u0441\u044b\u0437\u0431\u044b \u2014 \u043a\u0430\u0434\u0438\u043c\u043a\u0438 \u0436\u0430\u043d\u0430 \u0441\u044b\u043b\u044b\u043a \u0443\u0447\u0443\u0440\u0430\u0448\u0443\u0443.\n\u2022 \u0420\u0430\u0445\u043c\u0430\u0442 \u2014 \u042b\u0440\u0430\u0430\u0437\u044b\u0447\u044b\u043b\u044b\u043a.\n\u2022 \u041e\u043e\u0431\u0430 / \u0436\u043e\u043a \u2014 \u043c\u0430\u043a\u0443\u043b / \u043c\u0430\u043a\u0443\u043b \u044d\u043c\u0435\u0441.\n\u2022 \u041a\u0430\u043d\u0447\u0430? \u2014 \u041a\u0430\u043d\u0447\u0430\u0433\u0430?\n\u2022 \u041a\u0435\u0447\u0438\u0440\u0435\u0441\u0438\u0437 \u2014 \u041a\u0435\u0447\u0438\u0440\u0438\u043c \u0441\u0443\u0440\u0430\u0439\u043c.\n\u2022 \u0410\u043c\u0430\u043d \u0431\u043e\u043b\u0441\u0443\u043d \u2014 \u041a\u043e\u0448 \u0430\u0439\u0442\u044b\u0448\u0430 \u0442\u0443\u0440\u0433\u0430\u043d \u0436\u0430\u043a\u0448\u044b \u0442\u0438\u043b\u0435\u043a.\n\u041e\u0440\u0443\u0441 \u0442\u0438\u043b\u0438\u043d \u0434\u044d\u044d\u0440\u043b\u0438\u043a \u0431\u0430\u0430\u0440\u044b \u0442\u04af\u0448\u04af\u043d\u04e9\u0442; \u0430\u043d\u0433\u043b\u0438\u0441 \u0442\u0438\u043b\u0438 \u0411\u0438\u0448\u043a\u0435\u043a, \u041a\u0430\u0440\u0430\u043a\u043e\u043b \u0441\u044b\u044f\u043a\u0442\u0443\u0443 \u0442\u0443\u0440\u0438\u0441\u0442\u0442\u0438\u043a \u0436\u0435\u0440\u043b\u0435\u0440\u0434\u0435 \u043a\u0435\u04a3\u0438\u0440\u0438 \u043a\u043e\u043b\u0434\u043e\u043d\u0443\u043b\u0430\u0442."],t.s)
