B.a8c=new A.y(B.an,["Here are the places I know inside out:","\u0412\u043e\u0442 \u043c\u0435\u0441\u0442\u0430, \u043f\u0440\u043e \u043a\u043e\u0442\u043e\u0440\u044b\u0435 \u044f \u043c\u043e\u0433\u0443 \u0440\u0430\u0441\u0441\u043a\u0430\u0437\u0430\u0442\u044c \u0432 \u0434\u0435\u0442\u0430\u043b\u044f\u0445:","\u041c\u0435\u043d \u0436\u0430\u043a\u0448\u044b \u0431\u0438\u043b\u0433\u0435\u043d \u0436\u0435\u0440\u043b\u0435\u0440:"],t.w)
B.a8e=new A.y(B.an,["Visiting rules","\u041f\u0440\u0430\u0432\u0438\u043b\u0430 \u043f\u043e\u0441\u0435\u0449\u0435\u043d\u0438\u044f","\u0417\u044b\u044f\u0440\u0430\u0442 \u044d\u0440\u0435\u0436\u0435\u043b\u0435\u0440\u0438"],t.w)
B.a1m=s(["Kyrgyz traditions blend Tengrism, Sufi Islam and nomadic codes. Hosts serve guests first; elders are addressed with respect; the right hand is used for greetings and gifts. Spring brings Nooruz (March 21) \u2014 fires, sumolok porridge cooked overnight and horseback games like kok-boru."],t.s)
B.a3N=s(["\u0422\u0440\u0430\u0434\u0438\u0446\u0438\u0438 \u043a\u044b\u0440\u0433\u044b\u0437\u043e\u0432 \u0441\u043e\u0447\u0435\u0442\u0430\u044e\u0442 \u0442\u0435\u043d\u0433\u0440\u0438\u0430\u043d\u0441\u0442\u0432\u043e, \u0441\u0443\u0444\u0438\u0439\u0441\u043a\u0438\u0439 \u0438\u0441\u043b\u0430\u043c \u0438 \u043a\u043e\u0447\u0435\u0432\u044b\u0435 \u043f\u0440\u0430\u0432\u0438\u043b\u0430. \u0413\u043e\u0441\u0442\u044f \u043e\u0431\u0441\u043b\u0443\u0436\u0438\u0432\u0430\u044e\u0442 \u043f\u0435\u0440\u0432\u044b\u043c; \u0441\u043e \u0441\u0442\u0430\u0440\u0448\u0438\u043c\u0438 \u0433\u043e\u0432\u043e\u0440\u044f\u0442 \u0441 \u043f\u043e\u0447\u0442\u0435\u043d\u0438\u0435\u043c; \u0437\u0434\u043e\u0440\u043e\u0432\u0430\u044e\u0442\u0441\u044f \u0438 \u043f\u043e\u0434\u0430\u044e\u0442 \u0432\u0435\u0449\u0438 \u043f\u0440\u0430\u0432\u043e\u0439 \u0440\u0443\u043a\u043e\u0439. \u0412\u0435\u0441\u043d\u043e\u0439 \u2014 \u041d\u043e\u043e\u0440\u0443\u0437 (21 \u043c\u0430\u0440\u0442\u0430): \u043a\u043e\u0441\u0442\u0440\u044b, \u043d\u043e\u0447\u043d\u043e\u0439 \u0441\u0443\u043c\u0430\u043b\u0430\u043a \u0438 \u0438\u0433\u0440\u044b \u043d\u0430 \u043b\u043e\u0448\u0430\u0434\u044f\u0445 (\u043a\u043e\u043a-\u0431\u043e\u0440\u0443)."],t.s)
B.a29=s(["\u041a\u044b\u0440\u0433\u044b\u0437 \u0441\u0430\u043b\u0442\u0442\u0430\u0440\u044b \u0442\u0435\u043d\u0433\u0440\u0438\u0437\u043c, \u0441\u0443\u0444\u0438\u0439 \u0438\u0441\u043b\u0430\u043c\u044b \u0436\u0430\u043d\u0430 \u043a\u04e9\u0447\u043c\u04e9\u043d \u044d\u0440\u0435\u0436\u0435\u043b\u0435\u0440\u0438\u043d\u0435\u043d \u043a\u0443\u0440\u0430\u043b\u0433\u0430\u043d. \u041a\u043e\u043d\u043e\u043a\u0442\u0443 \u0431\u0438\u0440\u0438\u043d\u0447\u0438 \u043a\u043e\u043d\u043e\u043a\u0442\u043e\u0448\u043e\u0442; \u0443\u043b\u0443\u0443\u043b\u0430\u0440\u0433\u0430 \u0441\u044b\u0439\u043b\u0430\u043f, \u043e\u04a3 \u043a\u043e\u043b \u043c\u0435\u043d\u0435\u043d \u0443\u0447\u0443\u0440\u0430\u0448\u0430\u0442 \u0436\u0430\u043d\u0430 \u0431\u0435\u043b\u0435\u043a \u0431\u0435\u0440\u0438\u0448\u0435\u0442. \u0416\u0430\u0437\u0434\u0430 \u2014 \u041d\u043e\u043e\u0440\u0443\u0437 (21-\u043c\u0430\u0440\u0442): \u043e\u0442 \u0436\u0430\u0433\u0443\u0443, \u0442\u04af\u043d \u0431\u043e\u044e \u0431\u044b\u0448\u043a\u0430\u043d \u0441\u04af\u043c\u04e9\u043b\u04e9\u043a, \u043a\u043e\u043a-\u0431\u043e\u0440\u0443 \u0441\u044b\u044f\u043a\u0442\u0443\u0443 \u0430\u0442 \u043e\u044e\u043d\u0434\u0430\u0440\u044b."],t.s)
B.a8f=new A.y(B.an,[B.a1m,B.a3N,B.a29],t.T)
B.a54=s(['A nomad walks into a yurt and says "I came back for my home" \u2014 turns out, the yurt was already two valleys away.',"Why is Issyk-Kul so warm? Because Lake Baikal got all the cold first.",'Tourist: "How long is the Manas epic?" Manaschy: "Bring tea \u2014 and maybe a sleeping bag."'],t.s)
B.a5V=s(["\u0422\u0443\u0440\u0438\u0441\u0442 \u0441\u043f\u0440\u0430\u0448\u0438\u0432\u0430\u0435\u0442: \xab\u0421\u043a\u043e\u043b\u044c\u043a\u043e \u0438\u0434\u0442\u0438 \u0434\u043e \u043f\u0435\u0440\u0435\u0432\u0430\u043b\u0430?\xbb \u2014 \u0427\u0430\u0431\u0430\u043d: \xab\u0411\u043b\u0438\u0437\u043a\u043e, \u0442\u043e\u043b\u044c\u043a\u043e \u0437\u0430 \u0442\u0435\u043c\u0438 \u0442\u0440\u0435\u043c\u044f \u0433\u043e\u0440\u0430\u043c\u0438.\xbb","\u041f\u043e\u0447\u0435\u043c\u0443 \u0418\u0441\u0441\u044b\u043a-\u041a\u0443\u043b\u044c \u0442\u0451\u043f\u043b\u044b\u0439? \u041f\u043e\u0442\u043e\u043c\u0443 \u0447\u0442\u043e \u0432\u0435\u0441\u044c \u0445\u043e\u043b\u043e\u0434 \u0437\u0430\u0431\u0440\u0430\u043b \u0411\u0430\u0439\u043a\u0430\u043b.","\u0422\u0443\u0440\u0438\u0441\u0442: \xab\u0410 \u0434\u043e\u043b\u0433\u043e \u0440\u0430\u0441\u0441\u043a\u0430\u0437\u044b\u0432\u0430\u044e\u0442 \u041c\u0430\u043d\u0430\u0441?\xbb \u2014 \u041c\u0430\u043d\u0430\u0441\u0447\u044b: \xab\u0414\u043e\u043b\u0435\u0439\u0442\u0435 \u0447\u0430\u0439 \u0438 \u0443\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0439\u0442\u0435\u0441\u044c \u043f\u043e\u0443\u0434\u043e\u0431\u043d\u0435\u0435.\xbb"],t.s)
B.a3u=s(["\u0422\u0443\u0440\u0438\u0441\u0442: \xab\u0410\u0448\u0443\u0443\u0433\u0430 \u043a\u0430\u043d\u0442\u0438\u043f \u0436\u0435\u0442\u0435\u043c?\xbb \u2014 \u041a\u043e\u0439\u0447\u0443: \xab\u0416\u0430\u043a\u044b\u043d \u044d\u043b\u0435, \u0443\u0448\u0443\u043b \u04af\u0447 \u0442\u043e\u043e\u043d\u0443\u043d \u0430\u0440\u043a\u0430\u0441\u044b\u043d\u0434\u0430.\xbb","\u042d\u043c\u043d\u0435 \u04af\u0447\u04af\u043d \u042b\u0441\u044b\u043a-\u041a\u04e9\u043b \u0436\u044b\u043b\u0443\u0443? \u0410\u043d\u0442\u043a\u0435\u043d\u0438 \u0431\u0430\u0440\u0434\u044b\u043a \u0441\u0443\u0443\u043a\u0442\u0443 \u0411\u0430\u0439\u043a\u0430\u043b \u0430\u043b\u044b\u043f \u043a\u043e\u0439\u0433\u043e\u043d.","\u0422\u0443\u0440\u0438\u0441\u0442: \xab\u041c\u0430\u043d\u0430\u0441 \u0443\u0437\u0430\u043a\u043f\u044b?\xbb \u2014 \u041c\u0430\u043d\u0430\u0441\u0447\u044b: \xab\u0427\u0430\u0439\u044b\u04a3\u0434\u044b \u043a\u0443\u044e\u043f, \u0436\u0430\u0439\u0433\u0430\u0448\u044b\u043f \u043e\u0442\u0443\u0440.\xbb"],t.s)
B.LJ=new A.y(B.an,[B.a54,B.a5V,B.a3u],t.T)
B.a2f=s(["Kyrgyzstan is more than 90% mountains \u2014 the Tian Shan range covers most of the country.",'Issyk-Kul is the world\'s second-largest alpine lake; "Ysyk-Kol" literally means "warm lake" \u2014 it almost never freezes.',"The Manas epic, recited by manaschys, is one of the longest oral epics in the world \u2014 about half a million lines.","The shyrdak \u2014 a hand-felted Kyrgyz carpet \u2014 is on the UNESCO list of intangible cultural heritage in need of urgent safeguarding.","Eagle hunters (berkutchi) train golden eagles for years; the eagle usually returns to the wild after a decade with its master."],t.s)
B.a3L=s(["\u0411\u043e\u043b\u044c\u0448\u0435 90% \u0442\u0435\u0440\u0440\u0438\u0442\u043e\u0440\u0438\u0438 \u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d\u0430 \u2014 \u0433\u043e\u0440\u044b. \u0422\u044f\u043d\u044c-\u0428\u0430\u043d\u044c \u0437\u0430\u043d\u0438\u043c\u0430\u0435\u0442 \u043f\u043e\u0447\u0442\u0438 \u0432\u0441\u044e \u0441\u0442\u0440\u0430\u043d\u0443.","\u0418\u0441\u0441\u044b\u043a-\u041a\u0443\u043b\u044c \u2014 \u0432\u0442\u043e\u0440\u043e\u0435 \u043f\u043e \u0432\u0435\u043b\u0438\u0447\u0438\u043d\u0435 \u0433\u043e\u0440\u043d\u043e\u0435 \u043e\u0437\u0435\u0440\u043e \u0432 \u043c\u0438\u0440\u0435; \u0438\u043c\u044f \u043e\u0437\u043d\u0430\u0447\u0430\u0435\u0442 \xab\u0442\u0451\u043f\u043b\u043e\u0435 \u043e\u0437\u0435\u0440\u043e\xbb \u2014 \u043e\u043d\u043e \u043f\u043e\u0447\u0442\u0438 \u043d\u0438\u043a\u043e\u0433\u0434\u0430 \u043d\u0435 \u0437\u0430\u043c\u0435\u0440\u0437\u0430\u0435\u0442.","\u042d\u043f\u043e\u0441 \xab\u041c\u0430\u043d\u0430\u0441\xbb \u2014 \u043e\u0434\u0438\u043d \u0438\u0437 \u0441\u0430\u043c\u044b\u0445 \u0434\u043b\u0438\u043d\u043d\u044b\u0445 \u0443\u0441\u0442\u043d\u044b\u0445 \u044d\u043f\u043e\u0441\u043e\u0432 \u043f\u043b\u0430\u043d\u0435\u0442\u044b, \u043e\u043a\u043e\u043b\u043e \u043f\u043e\u043b\u0443\u043c\u0438\u043b\u043b\u0438\u043e\u043d\u0430 \u0441\u0442\u0440\u043e\u043a, \u0435\u0433\u043e \u0438\u0441\u043f\u043e\u043b\u043d\u044f\u044e\u0442 \u043c\u0430\u043d\u0430\u0441\u0447\u044b.","\u041a\u044b\u0440\u0433\u044b\u0437\u0441\u043a\u0438\u0439 \u0448\u044b\u0440\u0434\u0430\u043a \u2014 \u0432\u043e\u0439\u043b\u043e\u0447\u043d\u044b\u0439 \u043a\u043e\u0432\u0451\u0440 \u0440\u0443\u0447\u043d\u043e\u0439 \u0440\u0430\u0431\u043e\u0442\u044b \u2014 \u0432\u043d\u0435\u0441\u0451\u043d \u0432 \u0441\u043f\u0438\u0441\u043e\u043a \u042e\u041d\u0415\u0421\u041a\u041e \u043a\u0430\u043a \u043d\u0435\u043c\u0430\u0442\u0435\u0440\u0438\u0430\u043b\u044c\u043d\u043e\u0435 \u043d\u0430\u0441\u043b\u0435\u0434\u0438\u0435, \u043d\u0443\u0436\u0434\u0430\u044e\u0449\u0435\u0435\u0441\u044f \u0432 \u0437\u0430\u0449\u0438\u0442\u0435.","\u0411\u0435\u0440\u043a\u0443\u0442\u0447\u0438 \u0433\u043e\u0434\u0430\u043c\u0438 \u043e\u0431\u0443\u0447\u0430\u044e\u0442 \u0431\u0435\u0440\u043a\u0443\u0442\u043e\u0432 \u043e\u0445\u043e\u0442\u0435; \u043e\u0431\u044b\u0447\u043d\u043e \u0447\u0435\u0440\u0435\u0437 \u0434\u0435\u0441\u044f\u0442\u043e\u043a \u043b\u0435\u0442 \u043f\u0442\u0438\u0446\u0443 \u043e\u0442\u043f\u0443\u0441\u043a\u0430\u044e\u0442 \u043e\u0431\u0440\u0430\u0442\u043d\u043e \u0432 \u0433\u043e\u0440\u044b."],t.s)
B.a1i=s(["\u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d\u0434\u044b\u043d 90%\u0434\u0430\u043d \u043a\u04e9\u0431\u04af \u0442\u043e\u043e\u043b\u043e\u0440\u0434\u043e\u043d \u0442\u0443\u0440\u0430\u0442 \u2014 \u04e9\u043b\u043a\u04e9\u043d\u04af \u043d\u0435\u0433\u0438\u0437\u0438\u043d\u0435\u043d \u0422\u044f\u043d\u044c-\u0428\u0430\u043d\u044c \u043a\u0430\u043f\u0442\u0430\u043f \u0442\u0443\u0440\u0430\u0442.",'\u042b\u0441\u044b\u043a-\u041a\u04e9\u043b \u2014 \u0434\u04af\u0439\u043d\u04e9\u0434\u04e9\u0433\u04af \u044d\u043a\u0438\u043d\u0447\u0438 \u0447\u043e\u04a3 \u0442\u043e\u043e\u043b\u0443\u0443 \u043a\u04e9\u043b; "\u044b\u0439\u044b\u043a" \u044d\u043c\u0435\u0441, "\u0436\u044b\u043b\u0443\u0443" \u043a\u04e9\u043b \u0434\u0435\u0433\u0435\u043d \u043c\u0430\u0430\u043d\u0438, \u0430\u043b \u0434\u044d\u044d\u0440\u043b\u0438\u043a \u0442\u043e\u04a3\u0431\u043e\u0439\u0442.',"\u041c\u0430\u043d\u0430\u0441 \u044d\u043f\u043e\u0441\u0443 \u2014 \u0436\u0435\u0440 \u0436\u04af\u0437\u04af\u043d\u0434\u04e9\u0433\u04af \u044d\u04a3 \u0443\u0437\u0443\u043d \u043e\u043e\u0437\u0435\u043a\u0438 \u0447\u044b\u0433\u0430\u0440\u043c\u0430\u043b\u0430\u0440\u0434\u044b\u043d \u0431\u0438\u0440\u0438, \u0436\u0430\u0440\u044b\u043c \u043c\u0438\u043b\u043b\u0438\u043e\u043d\u0433\u043e \u0436\u0430\u043a\u044b\u043d \u0441\u0430\u0431\u044b \u0431\u0430\u0440, \u0430\u043d\u044b \u043c\u0430\u043d\u0430\u0441\u0447\u044b\u043b\u0430\u0440 \u0430\u0439\u0442\u0430\u0442.","\u041a\u044b\u0440\u0433\u044b\u0437 \u0448\u044b\u0440\u0434\u0430\u0433\u044b \u2014 \u043a\u043e\u043b \u043c\u0435\u043d\u0435\u043d \u0431\u0430\u0441\u044b\u043b\u0433\u0430\u043d \u043a\u0438\u0439\u0438\u0437 \u043a\u0438\u043b\u0435\u043c \u2014 \u042e\u041d\u0415\u0421\u041a\u041e\u043d\u0443\u043d \u043a\u043e\u0440\u0433\u043e\u043e\u0433\u043e \u043c\u0443\u043a\u0442\u0430\u0436 \u043c\u0430\u0434\u0430\u043d\u0438\u0439 \u043c\u0443\u0440\u0430\u0441 \u0442\u0438\u0437\u043c\u0435\u0441\u0438\u043d\u0434\u0435.","\u0411\u04af\u0440\u043a\u04af\u0442\u0447\u04af\u043b\u04e9\u0440 \u0431\u04af\u0440\u043a\u04af\u0442\u0442\u04af \u0436\u044b\u043b\u0434\u0430\u0440 \u0431\u043e\u044e \u0442\u0430\u0440\u0431\u0438\u044f\u043b\u0430\u0448\u0430\u0442; \u0430\u0434\u0430\u0442\u0442\u0430 \u043e\u043d \u0436\u044b\u043b\u0434\u0430\u043d \u043a\u0438\u0439\u0438\u043d \u0431\u04af\u0440\u043a\u04af\u0442 \u043a\u0430\u0439\u0440\u0430 \u0442\u043e\u043e\u0433\u043e \u043a\u043e\u0451 \u0431\u0435\u0440\u0438\u043b\u0435\u0442."],t.s)
