B.a7X=new A.y(B.an,["The Burana minaret used to be 45 m tall but lost its top to a 15th-century earthquake \u2014 it now stands at 24 m with a spiral staircase you can climb.","\u0411\u0430\u0448\u043d\u044f \u0411\u0443\u0440\u0430\u043d\u0430 \u0440\u0430\u043d\u044c\u0448\u0435 \u0431\u044b\u043b\u0430 45 \u043c \u0432\u044b\u0441\u043e\u0442\u043e\u0439, \u043d\u043e \u0437\u0435\u043c\u043b\u0435\u0442\u0440\u044f\u0441\u0435\u043d\u0438\u0435 XV \u0432\u0435\u043a\u0430 \u0441\u043d\u0435\u0441\u043b\u043e \u0432\u0435\u0440\u0445\u0443\u0448\u043a\u0443 \u2014 \u0441\u0435\u0439\u0447\u0430\u0441 24 \u043c, \u0438 \u0432\u043d\u0443\u0442\u0440\u0438 \u0435\u0441\u0442\u044c \u0432\u0438\u043d\u0442\u043e\u0432\u0430\u044f \u043b\u0435\u0441\u0442\u043d\u0438\u0446\u0430.","\u0411\u0443\u0440\u0430\u043d\u0430 \u043c\u0443\u043d\u0430\u0440\u0430\u0441\u044b \u043c\u0443\u0440\u0434\u0430 45 \u043c \u0431\u0438\u0439\u0438\u043a \u0431\u043e\u043b\u0433\u043e\u043d, \u0431\u0438\u0440\u043e\u043a XV \u043a\u044b\u043b\u044b\u043c\u0434\u0430\u0433\u044b \u0436\u0435\u0440 \u0442\u0438\u0442\u0438\u0440\u04e9\u04e9 \u0443\u0447\u0443\u043d \u0436\u043e\u043a \u043a\u044b\u043b\u0433\u0430\u043d \u2014 \u0430\u0437\u044b\u0440 24 \u043c, \u0438\u0447\u0438\u043d\u0434\u0435 \u0438\u0439\u0440\u0438\u043b\u0433\u0435\u043d \u0442\u0435\u043f\u043a\u0438\u0447 \u0431\u0430\u0440."],t.w)
B.a8a=new A.y(B.an,["Sulaiman-Too is the only UNESCO World Heritage cultural site in Kyrgyzstan and has been a place of pilgrimage for at least 1,500 years.","\u0421\u0443\u043b\u0430\u0439\u043c\u0430\u043d-\u0422\u043e\u043e \u2014 \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u0439 \u043a\u0443\u043b\u044c\u0442\u0443\u0440\u043d\u044b\u0439 \u043e\u0431\u044a\u0435\u043a\u0442 \u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d\u0430 \u0432 \u0441\u043f\u0438\u0441\u043a\u0435 \u042e\u041d\u0415\u0421\u041a\u041e, \u043f\u0430\u043b\u043e\u043c\u043d\u0438\u043a\u0438 \u043f\u0440\u0438\u0445\u043e\u0434\u044f\u0442 \u0441\u044e\u0434\u0430 \u0443\u0436\u0435 \u043c\u0438\u043d\u0438\u043c\u0443\u043c 1500 \u043b\u0435\u0442.","\u0421\u0443\u043b\u0430\u0439\u043c\u0430\u043d-\u0422\u043e\u043e \u2014 \u041a\u044b\u0440\u0433\u044b\u0437\u0441\u0442\u0430\u043d\u0434\u0430\u0433\u044b \u042e\u041d\u0415\u0421\u041a\u041e\u043d\u0443\u043d \u043c\u0430\u0434\u0430\u043d\u0438\u0439 \u043c\u0443\u0440\u0430\u0441 \u0442\u0438\u0437\u043c\u0435\u0441\u0438\u043d\u0434\u0435\u0433\u0438 \u0436\u0430\u043b\u0433\u044b\u0437 \u043e\u0431\u044a\u0435\u043a\u0442, \u0437\u044b\u044f\u0440\u0430\u0442\u0447\u044b\u043b\u0430\u0440 \u0431\u0443\u043b \u0436\u0435\u0440\u0433\u0435 \u043a\u0435\u043c\u0438\u043d\u0434\u0435 1500 \u0436\u044b\u043b\u0434\u0430\u043d \u0431\u0435\u0440\u0438 \u0431\u0430\u0440\u044b\u043f \u043a\u0435\u043b\u0438\u0448\u0435\u0442."],t.w)
B.a7R=new A.y(B.an,["Tash-Rabat sits at 3,200 m and was a fortified caravanserai on a branch of the Silk Road; locals say its inner chambers stay cool even in July.","\u0422\u0430\u0448-\u0420\u0430\u0431\u0430\u0442 \u0441\u0442\u043e\u0438\u0442 \u043d\u0430 3200 \u043c \u0438 \u0431\u044b\u043b \u0443\u043a\u0440\u0435\u043f\u043b\u0451\u043d\u043d\u044b\u043c \u043a\u0430\u0440\u0430\u0432\u0430\u043d-\u0441\u0430\u0440\u0430\u0435\u043c \u043d\u0430 \u0412\u0435\u043b\u0438\u043a\u043e\u043c \u0428\u0451\u043b\u043a\u043e\u0432\u043e\u043c \u043f\u0443\u0442\u0438; \u043c\u0435\u0441\u0442\u043d\u044b\u0435 \u0433\u043e\u0432\u043e\u0440\u044f\u0442, \u0447\u0442\u043e \u0432\u043d\u0443\u0442\u0440\u0438 \u043f\u0440\u043e\u0445\u043b\u0430\u0434\u043d\u043e \u0434\u0430\u0436\u0435 \u0432 \u0438\u044e\u043b\u0435.","\u0422\u0430\u0448-\u0420\u0430\u0431\u0430\u0442 3200 \u043c \u0431\u0438\u0439\u0438\u043a\u0442\u0438\u043a\u0442\u0435 \u2014 \u0416\u0438\u0431\u0435\u043a \u0416\u043e\u043b\u0443\u043d\u0443\u043d \u0442\u0430\u0440\u043c\u0430\u0433\u044b\u043d\u0434\u0430\u0433\u044b \u043a\u043e\u0440\u0433\u043e\u043d\u0433\u043e\u043d \u043a\u0435\u0440\u0431\u0435\u043d \u0441\u0430\u0440\u0430\u0439\u044b; \u0436\u0435\u0440\u0433\u0438\u043b\u0438\u043a\u0442\u04af\u04af \u044d\u043b \u0430\u043d\u044b\u043d \u0438\u0447\u0438 \u0438\u044e\u043b\u0434\u0430 \u0434\u0430 \u0441\u0430\u043b\u043a\u044b\u043d \u0434\u0435\u043f \u0430\u0439\u0442\u0430\u0442."],t.w)
B.a8_=new A.y(B.an,["At 668 m deep, Issyk-Kul is the second deepest alpine lake on Earth \u2014 only Lake Baikal is deeper.","\u0418\u0441\u0441\u044b\u043a-\u041a\u0443\u043b\u044c \u2014 \u0432\u0442\u043e\u0440\u043e\u0435 \u043f\u043e \u0433\u043b\u0443\u0431\u0438\u043d\u0435 \u0433\u043e\u0440\u043d\u043e\u0435 \u043e\u0437\u0435\u0440\u043e \u043f\u043b\u0430\u043d\u0435\u0442\u044b (668 \u043c), \u0433\u043b\u0443\u0431\u0436\u0435 \u043d\u0435\u0433\u043e \u0442\u043e\u043b\u044c\u043a\u043e \u0411\u0430\u0439\u043a\u0430\u043b.","\u042b\u0441\u044b\u043a-\u041a\u04e9\u043b \u2014 \u0436\u0435\u0440 \u0436\u04af\u0437\u04af\u043d\u0434\u04e9\u0433\u04af \u0442\u0435\u0440\u0435\u04a3\u0434\u0438\u0433\u0438 \u0431\u043e\u044e\u043d\u0447\u0430 \u044d\u043a\u0438\u043d\u0447\u0438 \u0442\u043e\u043e\u043b\u0443\u0443 \u043a\u04e9\u043b (668 \u043c), \u0430\u043d\u0434\u0430\u043d \u0442\u0435\u0440\u0435\u04a3\u0438 \u0411\u0430\u0439\u043a\u0430\u043b \u0433\u0430\u043d\u0430."],t.w)
B.a7S=new A.y(B.an,["Son-Kul plateau sits at over 3,000 m and is empty in winter \u2014 shepherds set up yurts only from June to September.","\u041f\u043b\u0430\u0442\u043e \u0421\u043e\u043d-\u041a\u0443\u043b\u044c \u043d\u0430\u0445\u043e\u0434\u0438\u0442\u0441\u044f \u0432\u044b\u0448\u0435 3000 \u043c, \u0437\u0438\u043c\u043e\u0439 \u043e\u043d\u043e \u043f\u0443\u0441\u0442\u0443\u0435\u0442 \u2014 \u0447\u0430\u0431\u0430\u043d\u044b \u0441\u0442\u0430\u0432\u044f\u0442 \u044e\u0440\u0442\u044b \u0442\u043e\u043b\u044c\u043a\u043e \u0441 \u0438\u044e\u043d\u044f \u043f\u043e \u0441\u0435\u043d\u0442\u044f\u0431\u0440\u044c.","\u0421\u043e\u043d-\u041a\u04e9\u043b \u04e9\u0440\u04e9\u04e9\u043d\u04af 3000 \u043c \u0431\u0438\u0439\u0438\u043a\u0442\u0435, \u043a\u044b\u0448\u044b\u043d\u0434\u0430 \u0431\u043e\u0448 \u043a\u0430\u043b\u0430\u0442 \u2014 \u043a\u043e\u0439\u0447\u0443\u043b\u0430\u0440 \u0436\u0430\u0439\u043b\u043e\u043e\u0433\u043e \u0438\u044e\u043d\u0434\u0430\u043d \u0441\u0435\u043d\u0442\u044f\u0431\u0440\u044c\u0433\u0430 \u0447\u0435\u0439\u0438\u043d \u0433\u0430\u043d\u0430 \u043a\u04e9\u0447\u04af\u043f \u043a\u0435\u043b\u0438\u0448\u0435\u0442."],t.w)
B.a8d=new A.y(B.an,["Ala-Archa national park gates are only 40 km from central Bishkek \u2014 you can have breakfast in the city and lunch under a glacier.","\u0412\u043e\u0440\u043e\u0442\u0430 \u0410\u043b\u0430-\u0410\u0440\u0447\u0438 \u0432\u0441\u0435\u0433\u043e \u0432 40 \u043a\u043c \u043e\u0442 \u0446\u0435\u043d\u0442\u0440\u0430 \u0411\u0438\u0448\u043a\u0435\u043a\u0430 \u2014 \u043c\u043e\u0436\u043d\u043e \u043f\u043e\u0437\u0430\u0432\u0442\u0440\u0430\u043a\u0430\u0442\u044c \u0432 \u0433\u043e\u0440\u043e\u0434\u0435 \u0438 \u043e\u0431\u0435\u0434\u0430\u0442\u044c \u0443 \u043b\u0435\u0434\u043d\u0438\u043a\u0430.","\u0410\u043b\u0430-\u0410\u0440\u0447\u0430\u043d\u044b\u043d \u0434\u0430\u0440\u0431\u0430\u0437\u0430\u0441\u044b \u0411\u0438\u0448\u043a\u0435\u043a\u0442\u0438\u043d \u0431\u043e\u0440\u0431\u043e\u0440\u0443\u043d\u0430\u043d 40 \u043a\u043c \u0430\u043b\u044b\u0441 \u2014 \u0442\u0430\u04a3\u043a\u044b \u0442\u0430\u043c\u0430\u043a\u0442\u044b \u0448\u0430\u0430\u0440\u0434\u0430, \u0442\u04af\u0448\u043a\u04af \u0442\u0430\u043c\u0430\u043a\u0442\u044b \u043c\u04e9\u04a3\u0433\u04af\u043d\u04af\u043d \u0442\u04af\u0431\u04af\u043d\u0434\u04e9 \u0438\u0447\u0441\u0435 \u0431\u043e\u043b\u043e\u0442."],t.w)
